import React, { useState, useRef, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { getSocket } from '../socket';
import { showAdBeforeCall, triggerAdOnInteraction } from '../utils/adUtils';
import api from '../api';
import './VideoCall.css';

const VideoCall = ({ partner, roomId, onEndCall }) => {
  const { user } = useAuth();
  const [callStatus, setCallStatus] = useState('idle'); // idle, calling, connected, ended
  const [localStream, setLocalStream] = useState(null);
  const [remoteStream, setRemoteStream] = useState(null);
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);

  const localVideoRef = useRef(null);
  const remoteVideoRef = useRef(null);
  const peerConnection = useRef(null);

  const ICE_SERVERS = {
    iceServers: [
      { urls: 'stun:stun.l.google.com:19302' },
      { urls: 'stun:stun1.l.google.com:19302' },
    ]
  };

  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;

    socket.on('video_offer', handleOffer);
    socket.on('video_answer', handleAnswer);
    socket.on('ice_candidate', handleIceCandidate);
    socket.on('video_call_ended', () => {
      cleanupCall();
      setCallStatus('ended');
    });

    return () => {
      socket.off('video_offer');
      socket.off('video_answer');
      socket.off('ice_candidate');
      socket.off('video_call_ended');
      cleanupCall();
    };
  }, []);

  useEffect(() => {
    if (localStream && localVideoRef.current) {
      localVideoRef.current.srcObject = localStream;
    }
  }, [localStream]);

  useEffect(() => {
    if (remoteStream && remoteVideoRef.current) {
      remoteVideoRef.current.srcObject = remoteStream;
    }
  }, [remoteStream]);

  const incrementCallCount = async () => {
    try {
      await api.post('/users/increment-call', { userId: user._id });
    } catch (error) {
      console.error('Error incrementing call count:', error);
    }
  };

  const startCall = async () => {
    try {
      // Get user media
      const stream = await navigator.mediaDevices.getUserMedia({
        video: true,
        audio: true
      });
      setLocalStream(stream);
      setCallStatus('calling');

      // Create peer connection
      peerConnection.current = new RTCPeerConnection(ICE_SERVERS);

      // Add local stream tracks
      stream.getTracks().forEach(track => {
        peerConnection.current.addTrack(track, stream);
      });

      // Handle remote stream
      peerConnection.current.ontrack = (event) => {
        setRemoteStream(event.streams[0]);
        setCallStatus('connected');
      };

      // Handle ICE candidates
      peerConnection.current.onicecandidate = (event) => {
        if (event.candidate) {
          const socket = getSocket();
          socket.emit('ice_candidate', {
            roomId,
            candidate: event.candidate,
            to: partner._id
          });
        }
      };

      // Create and send offer
      const offer = await peerConnection.current.createOffer();
      await peerConnection.current.setLocalDescription(offer);

      const socket = getSocket();
      socket.emit('video_offer', {
        roomId,
        offer,
        to: partner._id,
        from: user._id
      });

      // Increment call count after starting
      await incrementCallCount();

    } catch (error) {
      console.error('Error starting call:', error);
      alert('Could not access camera/microphone. Please allow permissions.');
      setCallStatus('idle');
    }
  };

  const handleOffer = async (data) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: true,
        audio: true
      });
      setLocalStream(stream);

      peerConnection.current = new RTCPeerConnection(ICE_SERVERS);

      stream.getTracks().forEach(track => {
        peerConnection.current.addTrack(track, stream);
      });

      peerConnection.current.ontrack = (event) => {
        setRemoteStream(event.streams[0]);
        setCallStatus('connected');
      };

      peerConnection.current.onicecandidate = (event) => {
        if (event.candidate) {
          const socket = getSocket();
          socket.emit('ice_candidate', {
            roomId,
            candidate: event.candidate,
            to: data.from
          });
        }
      };

      await peerConnection.current.setRemoteDescription(new RTCSessionDescription(data.offer));
      const answer = await peerConnection.current.createAnswer();
      await peerConnection.current.setLocalDescription(answer);

      const socket = getSocket();
      socket.emit('video_answer', {
        roomId,
        answer,
        to: data.from
      });

      setCallStatus('connected');
    } catch (error) {
      console.error('Error handling offer:', error);
    }
  };

  const handleAnswer = async (data) => {
    try {
      await peerConnection.current.setRemoteDescription(new RTCSessionDescription(data.answer));
    } catch (error) {
      console.error('Error handling answer:', error);
    }
  };

  const handleIceCandidate = async (data) => {
    try {
      if (peerConnection.current) {
        await peerConnection.current.addIceCandidate(new RTCIceCandidate(data.candidate));
      }
    } catch (error) {
      console.error('Error handling ICE candidate:', error);
    }
  };

  const cleanupCall = () => {
    if (localStream) {
      localStream.getTracks().forEach(track => track.stop());
    }
    if (peerConnection.current) {
      peerConnection.current.close();
    }
    setLocalStream(null);
    setRemoteStream(null);
    peerConnection.current = null;
  };

  const endCall = () => {
    const socket = getSocket();
    if (socket) {
      socket.emit('video_call_end', { roomId, from: user._id });
    }
    cleanupCall();
    setCallStatus('ended');
    if (onEndCall) onEndCall();
  };

  const toggleMute = () => {
    if (localStream) {
      localStream.getAudioTracks().forEach(track => {
        track.enabled = !track.enabled;
      });
      setIsMuted(!isMuted);
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      localStream.getVideoTracks().forEach(track => {
        track.enabled = !track.enabled;
      });
      setIsVideoOff(!isVideoOff);
    }
  };

  const initiateCall = () => {
    // Trigger ad on interaction
    triggerAdOnInteraction();

    // Check if user has free calls
    if (user.freeCallsUsed < 1) {
      // First call is free
      startCall();
    } else {
      // Show ad before subsequent calls
      showAdBeforeCall(() => {
        startCall();
      });
    }
  };

  return (
    <div className="video-call-container">
      {callStatus === 'idle' && (
        <div className="call-prompt">
          <div className="partner-preview">
            <div className={`partner-avatar ${partner?.gender?.toLowerCase()}`}>
              {partner?.nickname?.charAt(0).toUpperCase()}
            </div>
            <h3>{partner?.nickname}</h3>
            <span className={`gender-tag ${partner?.gender?.toLowerCase()}`}>
              {partner?.gender === 'Male' ? '👨' : '👩'} {partner?.gender}
            </span>
          </div>
          <button className="start-call-btn" onClick={initiateCall}>
            📹 Start Video Call
          </button>
          {user.freeCallsUsed >= 1 && (
            <p className="ad-notice">* Ad will play before call starts</p>
          )}
        </div>
      )}

      {callStatus === 'calling' && (
        <div className="calling-state">
          <div className="calling-animation">
            <div className={`caller-avatar ${user?.gender?.toLowerCase()}`}>
              {user?.nickname?.charAt(0).toUpperCase()}
            </div>
            <div className="calling-dots">
              <span></span><span></span><span></span>
            </div>
            <div className={`callee-avatar ${partner?.gender?.toLowerCase()}`}>
              {partner?.nickname?.charAt(0).toUpperCase()}
            </div>
          </div>
          <p>Calling {partner?.nickname}...</p>
          <button className="cancel-call-btn" onClick={endCall}>Cancel</button>
        </div>
      )}

      {callStatus === 'connected' && (
        <div className="call-active">
          <div className="video-grid">
            <div className="remote-video-container">
              <video ref={remoteVideoRef} autoPlay playsInline />
              <span className="video-label">{partner?.nickname}</span>
            </div>
            <div className="local-video-container">
              <video ref={localVideoRef} autoPlay playsInline muted />
              <span className="video-label">You</span>
            </div>
          </div>
          <div className="call-controls">
            <button 
              className={`control-btn ${isMuted ? 'active' : ''}`} 
              onClick={toggleMute}
            >
              {isMuted ? '🔇' : '🔊'}
            </button>
            <button 
              className={`control-btn ${isVideoOff ? 'active' : ''}`} 
              onClick={toggleVideo}
            >
              {isVideoOff ? '📷' : '📹'}
            </button>
            <button className="end-call-btn" onClick={endCall}>
              📞 End Call
            </button>
          </div>
        </div>
      )}

      {callStatus === 'ended' && (
        <div className="call-ended">
          <h3>Call Ended</h3>
          <button onClick={() => setCallStatus('idle')}>Start New Call</button>
        </div>
      )}
    </div>
  );
};

export default VideoCall;
